// HasSourceSession applies the HasEdge predicate on the "source_session" edge.
func HasSourceSession() predicate.InvestigationMemory {
	return predicate.InvestigationMemory(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SourceSessionTable, SourceSessionColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSourceSessionWith applies the HasEdge predicate on the "source_session" edge with a given conditions (other predicates).
func HasSourceSessionWith(preds ...predicate.AlertSession) predicate.InvestigationMemory {
	return predicate.InvestigationMemory(func(s *sql.Selector) {
		step := newSourceSessionStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

