// And groups predicates with the AND operator between them.
func And(predicates ...predicate.InvestigationMemory) predicate.InvestigationMemory {
	return predicate.InvestigationMemory(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.InvestigationMemory) predicate.InvestigationMemory {
	return predicate.InvestigationMemory(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.InvestigationMemory) predicate.InvestigationMemory {
	return predicate.InvestigationMemory(sql.NotPredicates(p))
}
